import { Component } from '@angular/core';
import { MatGridListModule } from '@angular/material/grid-list';
import { MatIcon } from '@angular/material/icon';
import { CommonModule } from '@angular/common';
import { MatIconModule } from '@angular/material/icon';
import { MatDialog, MatDialogConfig } from '@angular/material/dialog';
import { Router } from '@angular/router';
import { MasterSignalService } from './master.signal.service';
import { CreateClientComponent } from '../../components/create-client/create-client.component';
import { CreateVesselComponent } from '../../components/create-vessel/create-vessel.component';
import { CreateCargoComponent } from '../../components/create-cargo/create-cargo.component';
import { CreatePurposeComponent } from '../../components/create-purpose/create-purpose.component';
import { CreatePortAgentComponent } from '../../components/create-port-agent/create-port-agent.component';
import { CreateUserComponent } from '../../components/create-user/create-user.component';
import { tabs } from './master.utils';
import { CreatePortTariffComponent } from '../../components/create-port-tariff/create-port-tariff.component';
import { CreateTariffServiceComponent } from '../../components/create-tariff-service/create-tariff-service.component';

@Component({
  selector: 'app-master',
  standalone: true,
  imports: [MatGridListModule, MatIcon, CommonModule, MatIconModule],
  templateUrl: './master.component.html',
  styleUrl: './master.component.css'
})
export class MasterComponent {

  constructor(private dialog: MatDialog, private router: Router, private masterservice: MasterSignalService) { }

  // Array of icons, titles, description  and route to display in the master screen
  roleId = Number(sessionStorage.getItem('roleId'));

  tiles: any[] = this.roleId === 1 ? tabs : tabs.filter(tab => tab.title != "User Management");

  navigate(route: string, title: string) {
    this.masterservice.setMasterTabName(title)
    sessionStorage.setItem("masterTab", title)
    this.router.navigate(['layout/master/mastertabs'])
  }

  // method to pen the dialog of the respective tabs from the master screen
  openDialog(name: string) {
    // if (name === 'Country') {
    //   const dialogConfig = new MatDialogConfig();
    //   dialogConfig.position = { right: '0' };
    //   dialogConfig.height = '100%';
    //   dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
    //   this.dialog.open(CreateCountryComponent, dialogConfig);
    // }

    if (name === 'Client') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreateClientComponent, dialogConfig);
    }
    else if (name === 'Vessel') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreateVesselComponent, dialogConfig);
    }
    else if (name === 'Cargo') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreateCargoComponent, dialogConfig);
    }
    else if (name === 'Purpose') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreatePurposeComponent, dialogConfig);
    }
    else if (name === 'Port Agent') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreatePortAgentComponent, dialogConfig);
    }
    else if (name === 'Port & Tariff') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.width = '96vw';
      dialogConfig.maxWidth = '100vw';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreatePortTariffComponent, dialogConfig);
    }
    else if (name === 'User Management') {
      const dialogConfig = new MatDialogConfig();
      dialogConfig.position = { right: '0' };
      dialogConfig.height = '100%';
      dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      this.dialog.open(CreateUserComponent, dialogConfig);
    }
    else if (name === 'Tariff Fees') {
      // const dialogConfig = new MatDialogConfig();
      // dialogConfig.position = { right: '0' };
      // dialogConfig.height = '100%';
      // dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
      // this.dialog.open(CreateTariffServiceComponent, dialogConfig);
      this.navigate('layout/master/tariff-fees', 'Tariff Fees');
    }
  }
}
